(() => {
  const keyword = "cf_mock_20260304";
  const html = (document.documentElement?.outerHTML || '').toLowerCase();
  const matched = html.includes(keyword.toLowerCase());
  (() => {
  const ok = !!(matched);
  const title = (matched ? 'CF KEYWORD MATCHED' : 'CF KEYWORD MISSED');
  const detail = ('keyword=' + keyword);
  const id = 'cf-test-toast-center';
  let el = document.getElementById(id);
  if (!el) {
    el = document.createElement('div');
    el.id = id;
    el.style.cssText = [
      'position:fixed',
      'left:50%',
      'top:50%',
      'transform:translate(-50%,-50%)',
      'z-index:2147483647',
      'min-width:420px',
      'max-width:82vw',
      'padding:16px 18px',
      'border-radius:12px',
      'box-shadow:0 18px 40px rgba(0,0,0,.38)',
      'font:14px/1.45 ui-monospace,Consolas,monospace',
      'color:#fff'
    ].join(';');
    document.body.appendChild(el);
  }
  el.style.background = ok ? '#166534' : '#991b1b';
  const now = new Date().toLocaleTimeString();
  el.innerHTML = `
    <div style="font-size:18px;font-weight:700;margin-bottom:6px;">${title}</div>
    <div style="font-size:12px;opacity:.95;word-break:break-word;">${detail}</div>
    <div style="font-size:12px;opacity:.9;margin-top:4px;">time=${now}</div>
  `;
  if (window.__cfTestToastTimer) clearTimeout(window.__cfTestToastTimer);
  window.__cfTestToastTimer = setTimeout(() => {
    const box = document.getElementById(id);
    if (box && box.parentNode) box.parentNode.removeChild(box);
  }, 10000);
})();
  localStorage.setItem('cf_visual_check_last', JSON.stringify({ matched, keyword, time: new Date().toISOString() }));
})();

